import React, { useState } from 'react';
import { PatientCase, DiagnosticStatus, PatientInfo } from '../types';

interface NewCaseProps {
  onSubmit: (newCase: PatientCase) => void;
}

const NewCase: React.FC<NewCaseProps> = ({ onSubmit }) => {
  const [formData, setFormData] = useState<Partial<PatientInfo>>({
    name: '',
    age: 0,
    gender: 'Male',
    bloodType: 'O+',
    history: ''
  });
  const [symptoms, setSymptoms] = useState('');
  const [imaging, setImaging] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImaging(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newCase: PatientCase = {
      id: Math.random().toString(36).substr(2, 9),
      patient: {
        id: Math.random().toString(36).substr(2, 9),
        ...formData as PatientInfo
      },
      symptoms,
      imagingUrl: imaging || undefined,
      status: DiagnosticStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    onSubmit(newCase);
  };

  return (
    <div className="max-w-4xl mx-auto bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
      <header className="mb-8">
        <h1 className="text-2xl font-bold text-slate-800">New Diagnostic Intake</h1>
        <p className="text-slate-500 mt-1">Provide patient details and clinical observations for MedGemma analysis.</p>
      </header>

      <form onSubmit={handleSubmit} className="space-y-8">
        <section className="space-y-4">
          <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Patient Demographics</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
              <input 
                type="text" 
                required
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Age</label>
              <input 
                type="number" 
                required
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.age || ''}
                onChange={e => setFormData({...formData, age: parseInt(e.target.value)})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Gender</label>
              <select 
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.gender}
                onChange={e => setFormData({...formData, gender: e.target.value as any})}
              >
                <option>Male</option>
                <option>Female</option>
                <option>Other</option>
              </select>
            </div>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Clinical Observations</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Current Symptoms & Presentation</label>
              <textarea 
                required
                rows={4}
                placeholder="Describe current symptoms, onset, and duration..."
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={symptoms}
                onChange={e => setSymptoms(e.target.value)}
              ></textarea>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Relevant Medical History</label>
              <textarea 
                rows={3}
                placeholder="Chronic conditions, allergies, past procedures..."
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={formData.history}
                onChange={e => setFormData({...formData, history: e.target.value})}
              ></textarea>
            </div>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Imaging & Diagnostics (Optional)</h2>
          <div className="flex items-center justify-center w-full">
            <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-slate-300 border-dashed rounded-xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
              {imaging ? (
                <div className="relative w-full h-full p-2">
                  <img src={imaging} alt="Preview" className="w-full h-full object-contain" />
                  <button 
                    type="button"
                    onClick={(e) => { e.preventDefault(); setImaging(null); }}
                    className="absolute top-2 right-2 bg-red-500 text-white rounded-full p-1"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                  </button>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <svg className="w-10 h-10 mb-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
                  <p className="mb-2 text-sm text-slate-500 font-semibold">Click to upload medical imaging (X-Ray, MRI, Scans)</p>
                  <p className="text-xs text-slate-400">PNG, JPG or JPEG (Max. 5MB)</p>
                </div>
              )}
              <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
            </label>
          </div>
        </section>

        <div className="pt-4 border-t border-slate-100 flex justify-end gap-3">
          <button type="button" className="px-6 py-2 text-sm font-medium text-slate-600 hover:bg-slate-50 rounded-lg transition-colors">Cancel</button>
          <button type="submit" className="px-8 py-2 bg-blue-600 text-white text-sm font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all transform active:scale-95">Initiate AI Analysis</button>
        </div>
      </form>
    </div>
  );
};

export default NewCase;

import React from 'react';
import { PatientCase, DiagnosticStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface AnalysisViewProps {
  patientCase: PatientCase;
  onBack: () => void;
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ patientCase, onBack }) => {
  const result = patientCase.result;

  if (patientCase.status === DiagnosticStatus.ANALYZING) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6">
        <div className="relative">
          <div className="w-24 h-24 border-4 border-blue-100 rounded-full"></div>
          <div className="w-24 h-24 border-4 border-blue-600 rounded-full border-t-transparent animate-spin absolute top-0"></div>
        </div>
        <div className="text-center">
          <h2 className="text-xl font-bold text-slate-800">Processing Medical Intelligence</h2>
          <p className="text-slate-500 mt-2 max-w-md">MedGemma is analyzing symptoms, medical history, and imaging against clinical guidelines and peer-reviewed literature...</p>
        </div>
      </div>
    );
  }

  if (!result) return null;

  const chartData = result.differentials.map(d => ({
    name: d.condition,
    prob: d.probability * 100
  }));

  const riskColors = {
    'Low': 'bg-emerald-500',
    'Moderate': 'bg-amber-500',
    'High': 'bg-orange-500',
    'Critical': 'bg-red-600'
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      <header className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-slate-200 rounded-lg transition-colors">
            <svg className="w-5 h-5 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
          </button>
          <div>
            <h1 className="text-2xl font-bold text-slate-800">Diagnostic Analysis Report</h1>
            <p className="text-sm text-slate-500">Case ID: {patientCase.id} • {patientCase.patient.name}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium text-slate-500 uppercase">Risk Level:</span>
          <span className={`px-3 py-1 rounded-full text-white text-xs font-bold ${riskColors[result.riskAssessment]}`}>
            {result.riskAssessment}
          </span>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Summary & Differentials */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-wider">Clinical Summary</h3>
            <p className="text-slate-700 leading-relaxed text-lg italic">"{result.summary}"</p>
          </div>

          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-wider">Differential Probabilities</h3>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} layout="vertical" margin={{ left: 40, right: 40 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" domain={[0, 100]} hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 12, fontWeight: 500 }} />
                  <Tooltip 
                    cursor={{ fill: 'transparent' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    formatter={(value: number) => [`${value.toFixed(1)}%`, 'Probability']}
                  />
                  <Bar dataKey="prob" radius={[0, 4, 4, 0]} barSize={32}>
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index === 0 ? '#2563eb' : '#94a3b8'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-100">
              <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Condition Rationales</h3>
            </div>
            <div className="divide-y divide-slate-100">
              {result.differentials.map((d, i) => (
                <div key={i} className="p-6">
                  <div className="flex justify-between items-start mb-2">
